function HeroSection() {
  return (
    <section className="hero" id="hero">
      <div className="hero-overlay" />
      <div className="hero-content reveal">
        <p className="eyebrow">WATCH ANYWHERE. CANCEL ANYTIME</p>
        <h1>See what&apos;s next</h1>
        <p className="hero-copy">
          Stream cinematic originals, award-winning series, and blockbuster
          films across every screen you own.
        </p>
        <button className="btn btn-red btn-large ripple">
          WATCH FREE FOR 30 DAYS
        </button>
      </div>
    </section>
  );
}

export default HeroSection;
